import{_ as l,o as a,c as p,a5 as i}from"./chunks/framework.B5tqjWbr.js";const L=JSON.parse('{"title":"教程 0016：单相锁相环（phase-locked loop / PLL）的带宽取舍","description":"","frontmatter":{"title":"教程 0016：单相锁相环（phase-locked loop / PLL）的带宽取舍","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0016-single-phase-pll-bandwidth.html","status":"learning","visibility":"public","summary":"Imported from 0016-single-phase-pll-bandwidth.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0016-single-phase-pll-bandwidth.md","filePath":"content/power/lessons/0016-single-phase-pll-bandwidth.md","lastUpdated":null}'),o={name:"content/power/lessons/0016-single-phase-pll-bandwidth.md"};function t(n,e,s,d,r,h){return a(),p("div",null,[...e[0]||(e[0]=[i(`<h1 id="教程-0016-单相锁相环-phase-locked-loop-pll-的带宽取舍" tabindex="-1">教程 0016：单相锁相环（phase-locked loop / PLL）的带宽取舍 <a class="header-anchor" href="#教程-0016-单相锁相环-phase-locked-loop-pll-的带宽取舍" aria-label="Permalink to &quot;教程 0016：单相锁相环（phase-locked loop / PLL）的带宽取舍&quot;">​</a></h1><p>中文主讲，一个概念，一个仿真任务：PLL 带宽越高，响应越快，但越容易把相位噪声变成频率和角度抖动。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学模型和教学参数，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>PLL 的带宽（bandwidth）描述它愿意多快相信相位误差信号。带宽高，PLL 对相位阶跃和频率变化反应快；带宽低，PLL 对噪声和谐波更不敏感，但跟踪会慢。</p><p>本节只讲一个概念：PLL 带宽不是越高越好，而是在响应速度和噪声敏感度之间取舍。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里，PLL 角度会被功率因数校正（power factor correction / PFC）、旁路（bypass）同步和逆变器控制复用。</p><ul><li><p>PLL 太慢：旁路同步、电网扰动恢复和频率变化跟踪会慢。</p></li><li><p>PLL 太快：输入电压噪声、谐波、采样毛刺会变成角度抖动。</p></li><li><p>角度抖动会进一步影响 PFC 电流参考、并机同步和旁路切换判断。</p></li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>PLL 像一个追着电网相位转的指针。高带宽像方向盘很灵：急转弯跟得快，但路面小抖动也会传进来。低带宽像方向盘更稳：小抖动不明显，但急转弯跟得慢。</p><pre><code>相位误差
阶跃 + 噪声

低带宽PLL
慢，但平滑

高带宽PLL
快，但抖动

工程选择
速度 vs 抗噪

带宽选择服务具体模式：PFC、旁路同步、逆变同步不一定相同
</code></pre><p>图 1：PLL 带宽是速度和抗噪之间的工程取舍。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>同步旋转坐标系（synchronous reference frame / SRF）PLL 的最小形式仍然是：</p><p>vq = sin(theta_grid - theta_hat) omega_hat = omega_nominal + Kp * vq + integral(Ki * vq) theta_hat[k+1] = theta_hat[k] + omega_hat * Ts</p><p>这里 <code>Kp</code> 和 <code>Ki</code> 来自比例积分控制器（proportional-integral controller / PI）。本节把较大的 <code>Kp</code>/<code>Ki</code> 视为较高带宽。相同的相位噪声（phase noise）输入下，高带宽 PLL 的估算频率（estimated frequency / f_est）会有更明显纹波。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_pll_bandwidth.py</p><p>脚本会生成并自动打开图；如果无法自动打开，会打印完整路径。图里包含带相位噪声的电网电压、慢 PLL 和快 PLL 的相位误差、估算频率、频率纹波 RMS 对比和参数框。</p><pre><code>一个仿真任务
python simulations\\python\\single_phase_pll_bandwidth.py --noise-phase-deg 0.5 --output simulations\\results\\pll_bandwidth_low_noise.png
</code></pre><p>python simulations\\python\\single_phase_pll_bandwidth.py --noise-phase-deg 4.0 --output simulations\\results\\pll_bandwidth_high_noise.png</p><p>对比低噪声和高噪声：噪声越大，快 PLL 的 <code>f_est</code> 纹波越明显。</p><p>观察顺序：</p><ul><li><p>先看相位阶跃后，快 PLL 的相位误差是否更快回到 ±5 度范围。</p></li><li><p>再看估算频率曲线，快 PLL 是否更抖。</p></li><li><p>最后看柱状图，确认频率噪声 RMS 对比。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里带宽不一定直接叫 <code>bandwidth</code>，它通常体现在 PI 增益、滤波器、限幅和锁定判据里：</p><p>phase detector vq -&gt; optional filter -&gt; PI gains Kp, Ki -&gt; frequency limit -&gt; phase accumulator -&gt; lock detector</p><ul><li><p>PFC、旁路同步、并机同步可能使用不同 PLL 带宽或锁定条件。</p></li><li><p>输入电压质量差时，PLL 前端滤波和带宽选择同样重要。</p></li><li><p>频率估算需要限幅，防止噪声或采样异常造成相位飞掉。</p></li><li><p>锁定判断要看持续时间内的相位误差和频率误差。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**带宽越高，PLL 越高级。 **纠正：**带宽高只是响应快，不代表抗噪好。</p></li><li><p>**误解：**带宽只影响相位误差。 **纠正：**带宽还影响估算频率抖动，进而影响依赖角度的电流参考和同步判断。</p></li><li><p>**误解：**仿真里锁得快，工程里也一定好。 **纠正：**真实电网有谐波、跌落、过零畸变和采样噪声，必须看扰动下表现。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释 PLL 带宽为什么影响响应速度。</p></li><li><p>能解释高带宽为什么更容易把相位噪声变成 <code>f_est</code> 纹波。</p></li><li><p>能在图中指出慢 PLL、快 PLL、相位误差、估算频率和频率纹波 RMS。</p></li><li><p>能说明为什么 PFC 和旁路同步可能不使用同一个带宽。</p></li><li><p>能基于仿真图准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么快 PLL 相位收敛更快，但频率估算更抖？</p></li><li><p>如果电网电压含明显谐波，你会倾向提高还是降低 PLL 带宽？为什么？</p></li><li><p>如果旁路切换要求很快确认同步，带宽和锁定判据应怎样一起考虑？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_pll_bandwidth.py</code> 看到快 PLL 收敛快，但 <code>f_est</code> 纹波更大。公司 UPS 的 PFC、旁路同步和逆变同步是否使用不同 PLL 带宽？</p></li><li><p>图中相位噪声为 2 度时，快 PLL 的频率纹波明显更大。实际代码里是否会对 <code>vq</code> 或 <code>f_est</code> 做滤波？</p></li><li><p>公司平台的 PLL 锁定判据是固定 ±几度、固定频率误差，还是随模式和电网质量变化？</p></li></ul><p>**下一步：**继续 PLL 的工程化：频率限幅、锁定判据和异常电网检测。</p><p>关联：<a href="./0015-single-phase-srf-pll.html">上一节：单相 SRF-PLL 入门</a>；源稿：<code>concepts/control/single-phase-pll-bandwidth.md</code>。</p><pre><code>上一节：教程 0015：单相锁相环（phase-locked loop / PLL）入门
下一节：教程 0017：锁相环（phase-locked loop / PLL）的频率限幅与锁定检测
</code></pre>`,43)])])}const _=l(o,[["render",t]]);export{L as __pageData,_ as default};
